          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-black shadow-inner shrink-0 
              ${maker.role === 'DECISION' ? 'bg-slate-950' : maker.role === 'INFLUENCER' ? 'bg-blue-600' : 'bg-slate-400'}`}>
              {maker.name.substring(0, 1)}
