              <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{maker.department}</div>
            </div>
          </div>
        </div>
        {hasChildren && (
          <div className="flex gap-8 mt-10 relative">
            <div className="absolute -top-10 left-1/2 -translate-x-1/2 w-0.5 h-10 bg-slate-200"></div>
            {maker.children.map((child: any) => (
              <MakerNode key={child.id} maker={child} level={level + 1} />
