          </div>
        )}
      </div>
    );
  };

  const renderCooperationBadges = (coop: AppInMatrix['cooperation']) => {
    const badges = [];
    if (coop.promotion) badges.push({ label: '推广', color: 'bg-blue-100 text-blue-700' });
    if (coop.preinstall) badges.push({ label: '预装', color: 'bg-indigo-100 text-indigo-700' });
    if (coop.joint) badges.push({ label: '联运', color: 'bg-emerald-100 text-emerald-700' });
    if (coop.push) badges.push({ label: 'Push', color: 'bg-amber-100 text-amber-700' });

    return (
      <div className="flex flex-wrap gap-1 justify-center max-w-[100px]">
        {badges.map((b, i) => (
          <span key={i} className={`text-[8px] font-black px-1 py-0.5 rounded uppercase tracking-tighter ${b.color}`}>
            {b.label}
          </span>
        ))}
        {badges.length === 0 && <span className="text-[8px] font-black text-slate-300">无活跃业务</span>}
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300">

      {/* 1. 客户基本信息 */}
      <section className="bg-white rounded border border-slate-200 overflow-hidden shadow-sm">
         <div className="p-8 pb-0 flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex items-center gap-6">
              <ImageWithFallback src={client.logo} alt={client.name} className="w-20 h-20 rounded border border-slate-100 object-cover shadow-sm" fallbackText={client.name} size={32} />
              <div>
                <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{client.name}</h1>
                <div className="flex items-center gap-3 text-xs text-slate-500 mt-2 font-bold">
                  <span className="flex items-center gap-1"><Building size={12}/> {client.industry}</span>
                  <span className={`${client.stage === ClientStage.ACTIVE ? 'text-green-600' : 'text-red-600'}`}>{client.stage === ClientStage.ACTIVE ? '活跃状态' : '风险预警'}</span>
                </div>
              </div>
            </div>
         </div>
         <div className="px-8 pb-8 pt-2 grid grid-cols-1 md:grid-cols-3 gap-6 border-t border-slate-50 mt-4">
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">公司主体</div>
                <div className="text-sm font-bold text-slate-900 truncate">{client.corporateEntity}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">账户评级</div>
                <div className="flex items-center gap-1.5 text-amber-600 text-sm font-black uppercase"><Award size={14}/> {client.accountRating}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">年预算额</div>
                <div className="text-sm font-mono font-bold text-slate-900">¥{(client.financials.annualBudget/1000000).toFixed(1)}M</div>
             </div>
         </div>
      </section>

      {/* 2. 决策链条图谱 (已优化纵向汇报关系展示) */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm overflow-hidden">
        {renderSectionHeader("全链路组织图谱", <UserCheck size={16}/>)}
        <div className="py-8 flex justify-center overflow-x-auto min-h-[450px]">
          <div className="inline-flex gap-20">
            {teamTree.map((root: any) => (
              <MakerNode key={root.id} maker={root} level={0} />
            ))}
          </div>
        </div>
      </section>

      {/* 4. 年度预算执行 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
        {renderSectionHeader("年度预算执行情况 (YTD)", <Target size={16}/>)}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 mb-8">
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">年度预算额</div>
                <div className="text-xl font-black text-slate-900">¥{(client.financials.annualBudget/1000000).toFixed(1)}M</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">YoY:</span>
                  {renderComparison(budgetMetrics.budgetYoY)}
                </div>
            </div>
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">累计已消耗</div>
                <div className="text-xl font-black text-blue-600">¥{(client.financials.annualSpend/1000000).toFixed(1)}M</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">YoY同期:</span>
