                </div>
            </div>
            <div className="p-6 bg-slate-50 rounded border border-slate-100">
                <div className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">预算执行率</div>
                <div className="text-xl font-black text-slate-900">{((client.financials.annualSpend / client.financials.annualBudget) * 100).toFixed(1)}%</div>
                <div className="mt-2 text-[10px] flex items-center gap-1.5 font-bold uppercase">
                  <span className="text-slate-400">同期差异:</span>
