export enum ClientStage {
  PROSPECT = 'PROSPECT', 
  ACTIVE = 'ACTIVE',     
  CHURN = 'CHURN',       
}

export interface MetricPoint {
  date: string;
  value: number;
  comparison?: number; 
  ideal?: number;      
  forecast?: number;   
}

export interface MetricValue {
  current: number; // 年初至今总额
  yoy: number;    // 同比变化率 (%)
}

export interface AppInMatrix {
  id: string;
  name: string;
  icon: string;
  cooperation: {             // 合作业务：推广、预装、联运、Push
    promotion: boolean;      // 应用推广 (对应直投和DSP消耗)
    preinstall: boolean;     // 预装 (对应预装收入)
    joint: boolean;          // 联运 (对应联运收入)
    push: boolean;           // Push 联运 (对应Push 收入)
  };
  // 拆分后的消耗指标
  directSpend: MetricValue;  // 直投消耗
  dspSpend: MetricValue;     // DSP 消耗
  // 收入指标
  jointRevenue: MetricValue;      // 联运收入
  preinstallRevenue: MetricValue; // 预装收入
