const generateQualityData = (days: number, type: 'retention' | 'uninstall') => {
  const baseData = {
    retention: { AG: 48, 应用宝: 38, 抖音: 32, 微信: 40, 百度: 35, target: 45 },
    uninstall: { AG: 11, 应用宝: 18, 抖音: 25, 微信: 15, 百度: 20, target: 12 }
  };
  const factor = days === 1 ? 1 : days === 3 ? 0.8 : days === 7 ? 0.6 : 0.45;
  const variance = type === 'retention' ? 6 : 4;

  return ['10月', '11月', '12月', '01月', '02月', '03月'].map((month, idx) => {
    const agOscillation = idx === 1 ? -4 : idx === 4 ? 5 : idx === 5 ? 2 : 0;
    return {
      month,
      AG: (baseData[type].AG * factor) + agOscillation + (Math.random() * 2),
      应用宝: (baseData[type].应用宝 * factor) + (Math.random() * variance),
      抖音: (baseData[type].抖音 * factor) + (Math.random() * variance),
      微信: (baseData[type].微信 * factor) + (Math.random() * variance),
      百度: (baseData[type].百度 * factor) + (Math.random() * variance),
      target: baseData[type].target * factor
    };
  });
};

export const AppKnowledgeBase: React.FC<AppCKBProps> = ({ app, onBack }) => {
  const [dynamics] = useState(INITIAL_DYNAMICS);
  const [retentionDays, setRetentionDays] = useState(1);
  const [uninstallDays, setUninstallDays] = useState(1);

  const currentRetentionData = useMemo(() => generateQualityData(retentionDays, 'retention'), [retentionDays]);
  const currentUninstallData = useMemo(() => generateQualityData(uninstallDays, 'uninstall'), [uninstallDays]);

  const maxTotalVolume = useMemo(() => {
    return Math.max(...TREND_DATA.map(d => d.AG + d.应用宝 + d.抖音 + d.微信 + d.百度));
  }, []);

  const toPercent = (decimal: number) => {
    if (isNaN(decimal)) return '0%';
