import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse, CorporateWiki, AppIntelligence, DynamicInfo } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * 抓取公司全网实时新闻与动态
 */
export const fetchCompanyNews = async (companyName: string): Promise<DynamicInfo[]> => {
  const prompt = `
    请搜索并汇总关于“${companyName}”公司的最新实时动态（过去 30 天内）：
    1. 包含重要的财报发布、高管变动、重大合作、新产品发布或负面舆情。
    2. 每一条动态需要包含：日期、来源媒体名称、动态标题摘要、以及对广告投放预算的潜在影响评价（增加/减少/稳定）。

    输出要求：严格的 JSON 格式数组。
    结构：
    [
      {
        "date": "YYYY-MM-DD",
        "title": "动态标题",
        "content": "摘要详情",
        "type": "STRATEGY", // 可选: UPDATE, FINANCE, STRATEGY
        "budgetImpact": "UP" // 可选: UP, DOWN, STABLE
      }
    ]
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              title: { type: Type.STRING },
              content: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['UPDATE', 'FINANCE', 'STRATEGY'] },
              budgetImpact: { type: Type.STRING, enum: ['UP', 'DOWN', 'STABLE'] }
            },
            required: ['date', 'title', 'content', 'type', 'budgetImpact']
          }
        }
      }
    });

    const news = JSON.parse(response.text?.trim() || '[]');
    return news;
  } catch (e) {
    console.error("Fetch company news error:", e);
    return [];
  }
};

