  useEffect(() => {
    const loadNews = async () => {
      setLoadingNews(true);
      try {
        const result = await fetchCompanyNews(client.name);
        setNews(result);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingNews(false);
      }
    };
    loadNews();
