  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderSectionHeader = (title: string, icon: React.ReactNode) => (
    <div className="flex items-center gap-3 border-b border-slate-100 pb-4 mb-6">
      <div className="text-slate-900 bg-slate-100 p-1.5 rounded">{icon}</div>
      <div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">{title}</h3>
      </div>
    </div>
  );

  const teamTree = useMemo(() => {
    const makers = client.decisionTeam;
    const roots = makers.filter(m => !m.reportsTo);

    const buildTree = (parent: DecisionMaker): any => ({
      ...parent,
      children: makers.filter(m => m.reportsTo === parent.id).map(buildTree)
    });

    return roots.map(buildTree);
  }, [client.decisionTeam]);

  const budgetMetrics = useMemo(() => {
    const history = client.annualSpendHistory;
    const totalProjectedSpend = history.reduce((acc, m) => acc + (m.actual ?? m.forecast ?? 0), 0);
    const lastActualIdx = history.reduce((maxIdx, m, idx) => m.actual !== undefined ? idx : maxIdx, -1);
    const totalLastYearSpendToDate = history.slice(0, lastActualIdx + 1).reduce((acc, m) => acc + m.lastYearActual, 0);
    const totalLastYearSpendFull = history.reduce((acc, m) => acc + m.lastYearActual, 0);
    const lastYearBudget = totalLastYearSpendFull * 0.95;
    const lastYearUtilization = (totalLastYearSpendToDate / lastYearBudget) * 100;
    const currentUtilization = (client.financials.annualSpend / client.financials.annualBudget) * 100;

    const calcRate = (curr: number, prev: number) => prev === 0 ? 0 : ((curr - prev) / prev) * 100;

    return {
      totalProjectedSpend,
      totalLastYearSpendFull,
      budgetYoY: calcRate(client.financials.annualBudget, lastYearBudget),
      spendYoY: calcRate(client.financials.annualSpend, totalLastYearSpendToDate),
      utilizationDiff: currentUtilization - lastYearUtilization,
      projectionYoY: calcRate(totalProjectedSpend, totalLastYearSpendFull)
    };
  }, [client.annualSpendHistory, client.financials]);

