import { defineComponent, computed } from 'vue';
import { UserCheck, Share2 } from 'lucide-vue-next';
import OrgNode from './OrgNode.ts';

export default defineComponent({
  name: 'OrganizationChart',
  components: { UserCheck, Share2, OrgNode },
  props: ['makers'],
  emits: ['select'],
  setup(props) {
    const teamTree = computed(() => {
      const makers = props.makers;
      const roots = makers.filter((m: any) => !m.reportsTo);
      const buildTree = (parent: any) => ({
        ...parent,
        children: makers.filter((m: any) => m.reportsTo === parent.id).map(buildTree)
      });
      return roots.map(buildTree);
    });

    return { teamTree };
  },
