import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse, CorporateWiki, AppIntelligence, DynamicInfo } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchCompanyNews = async (companyName: string): Promise<DynamicInfo[]> => {
  const prompt = `搜索并汇总关于“${companyName}”的最新动态。输出 JSON 数组。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json'
      }
    });
    return JSON.parse(response.text?.trim() || '[]');
  } catch (e) {
    return [];
  }
};

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const prompt = `分析广告主 ${client.name} 的数据并提供摘要。输出 JSON。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });
    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    return { summary: "暂无分析数据", actionItems: [] };
  }
};

