    const initChart = () => {
      if (!chartRef.value) return;
      if (myChart) myChart.dispose();

      myChart = echarts.init(chartRef.value);
      const option = {
        tooltip: { trigger: 'axis', backgroundColor: 'rgba(255, 255, 255, 0.95)', textStyle: { color: '#0f172a' } },
