        xAxis: { 
          type: 'category', 
          boundaryGap: false, 
          data: props.history.map((h: any) => h.date), 
          axisLine: { show: false },
          axisTick: { show: false }
        },
        yAxis: { 
          type: 'value', 
          axisLine: { show: false }, 
          splitLine: { lineStyle: { type: 'dashed', color: '#f1f5f9' } },
          axisLabel: { formatter: '{value} M' }
        },
        series: [
          {
            name: '上年实际',
            type: 'line',
            data: props.history.map((h: any) => (h.lastYearActual / 1000000).toFixed(1)),
            itemStyle: { color: '#94a3b8' },
            lineStyle: { width: 2, type: 'dashed' },
            smooth: true,
            showSymbol: false
