 */
export const fetchAppIntelligence = async (appName: string): Promise<AppIntelligence> => {
  const prompt = `针对 App “${appName}” 进行全网情报检索，给出历程、动态和 AI 洞察。输出 JSON。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json'
      }
    });
    const data = JSON.parse(response.text?.trim() || '{}');
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => ({
      title: c.web?.title || '来源',
      uri: c.web?.uri || ''
    })) || [];
    return { ...data, sources };
  } catch (e) {
    return { milestones: [], recentDynamics: [], aiInsight: "", sources: [] };
  }
};

