const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * AI 解析非结构化文本，更新决策人字段
 */
export const parseDecisionMakerEdit = async (inputText: string): Promise<any> => {
  const prompt = `
    你是一个专业的数据抓取助手。请解析以下关于某公司决策人的描述文本，提取关键字段信息：
    描述文本：“${inputText}”

    提取规则：
    1. 职位 (title): 提取其最新职衔。
    2. 决策力 (decisionPower): 根据描述判断为 "HIGH" (高), "MEDIUM" (中), "LOW" (低)。默认 "MEDIUM"。
    3. 负责业务 (responsibleBusiness): 仅从以下选项中选择（可多选）："推广", "预装", "Push", "联运"。
    4. 工作履历 (workExperience): 提取或总结其过去任职经历，返回字符串数组。
    5. 教育背景 (education): 提取其毕业院校及学位信息，返回字符串数组。
    6. 备注 (remarks): 提取一些运营需要关注的性格偏好或背景点。

    输出要求：严格的 JSON 格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            decisionPower: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] },
            responsibleBusiness: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING, enum: ['推广', '预装', 'Push', '联运'] } 
            },
            workExperience: { type: Type.ARRAY, items: { type: Type.STRING } },
            education: { type: Type.ARRAY, items: { type: Type.STRING } },
            remarks: { type: Type.STRING }
          },
          required: ['title', 'decisionPower', 'responsibleBusiness', 'workExperience', 'education', 'remarks']
        }
      }
    });

    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    console.error("AI Parse Error:", e);
    throw e;
  }
};

