                    <span className="text-[9px] font-black px-2 py-0.5 bg-blue-100 text-blue-700 rounded uppercase tracking-tighter shrink-0">{item.type}</span>
                    <h4 className="text-sm font-black text-slate-900">{item.title}</h4>
                 </div>
                 <p className="text-xs text-slate-600 font-bold leading-relaxed">{item.content}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* 3. 组织图谱 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm overflow-hidden">
        <div className="flex items-center justify-between border-b border-slate-100 pb-4 mb-6">
           <div className="flex items-center gap-3">
              <div className="text-slate-900 bg-slate-100 p-1.5 rounded"><UserCheck size={16}/></div>
