            {teamTree.map((root: any) => (root && <MakerNode key={root.id} maker={root} level={0} />))}
          </div>
        </div>
      </section>

      {/* 决策人详情 Modal */}
      {selectedMaker && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setSelectedMaker(null)}></div>
