                <h3 className="text-2xl font-black text-slate-900 mb-1">{selectedMaker.name}</h3>
                <div className="flex items-center gap-2">
                   <Mail size={12} className="text-slate-400"/>
                   <span className="text-xs font-bold text-slate-500">{selectedMaker.contact}</span>
                </div>
              </div>
              <div className="absolute top-6 right-6 flex items-center gap-2">
                <button 
                  onClick={() => setIsAiEditing(true)}
                  className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded border border-blue-100 text-[10px] font-black uppercase tracking-widest hover:bg-blue-100 transition-colors"
                >
                  <Edit3 size={12}/> AI 智能更新
                </button>
                <button onClick={() => setSelectedMaker(null)} className="p-2 hover:bg-slate-200 rounded-full text-slate-400 transition-colors">
                  <X size={20} />
                </button>
              </div>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 text-left">
              {/* 信息栅格：职位与部门 */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-slate-50 rounded border border-slate-100">
                  <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 flex items-center gap-1.5">
                    <Briefcase size={12}/> 职位
                  </div>
                  <div className="text-sm font-bold text-slate-900">{selectedMaker.title}</div>
                </div>
                <div className="p-4 bg-slate-50 rounded border border-slate-100">
                  <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 flex items-center gap-1.5">
                    <Building size={12}/> 部门
                  </div>
                  <div className="text-sm font-bold text-slate-900">{selectedMaker.department}</div>
                </div>
              </div>

              {/* 决策力评估：独立区域 */}
              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <Award size={14}/> 决策力评估
                </h4>
                <div className={`p-4 rounded-lg border-2 ${
                  selectedMaker.decisionPower === 'HIGH' ? 'bg-emerald-50/50 border-emerald-100 text-emerald-900' :
                  selectedMaker.decisionPower === 'MEDIUM' ? 'bg-blue-50/50 border-blue-100 text-blue-900' :
                  'bg-slate-50 border-slate-100 text-slate-600'
                }`}>
                  <p className="text-sm font-black flex items-center gap-2">
                    <Zap size={14} className={selectedMaker.decisionPower === 'HIGH' ? 'text-emerald-500' : 'text-slate-400'}/>
                    当前决策权重评定为：{
                      selectedMaker.decisionPower === 'HIGH' ? '【核心决策人】 拥有最终审批权与资源分配权。' :
                      selectedMaker.decisionPower === 'MEDIUM' ? '【关键影响者】 对决策路径有重要建议权。' :
                      '【执行配合者】 负责具体业务落地与日常沟通。'
                    }
                  </p>
                </div>
              </div>

              {/* 负责业务：缩小按钮 */}
              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <Smartphone size={14}/> 负责业务
                </h4>
                <div className="grid grid-cols-4 gap-2">
                  {['推广', '预装', 'Push', '联运'].map((biz) => {
                    const isSelected = selectedMaker.responsibleBusiness?.includes(biz);
                    return (
                      <button 
                        key={biz}
                        onClick={() => toggleBusiness(biz)}
                        className={`flex items-center justify-center gap-1.5 py-1.5 px-2 rounded border transition-all font-black text-[10px] uppercase tracking-tighter
                          ${isSelected 
                            ? 'bg-slate-900 border-slate-950 text-white shadow-sm' 
                            : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'}`}
                      >
                        {isSelected ? <Check size={10}/> : <div className="w-2.5 h-2.5 border border-slate-100 rounded"></div>}
                        {biz}
                      </button>
                    );
                  })}
                </div>
              </div>

              {/* 教育背景卡片 */}
              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <GraduationCap size={14}/> 教育背景
                </h4>
                <div className="space-y-2">
                  {selectedMaker.education.length > 0 ? (
                    selectedMaker.education.map((edu, i) => (
                      <div key={i} className="text-sm font-bold text-slate-700 leading-relaxed bg-slate-50 px-3 py-2 rounded border border-slate-100">
                        {edu}
                      </div>
                    ))
                  ) : (
                    <div className="text-xs font-bold text-slate-400 italic">暂无教育背景记录</div>
                  )}
                </div>
              </div>

              {/* 工作履历 */}
              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <History size={14}/> 工作履历
                </h4>
                <div className="space-y-4">
                  {selectedMaker.workExperience.map((exp, i) => (
                    <div key={i} className="flex gap-4 group">
                      <div className="w-1.5 h-1.5 rounded-full bg-slate-300 mt-1.5 shrink-0 group-hover:bg-blue-500"></div>
                      <div className="text-sm font-bold text-slate-700 leading-relaxed">{exp}</div>
                    </div>
                  ))}
                </div>
              </div>

              {/* 备注区域 */}
              <div className="p-5 bg-amber-50 rounded-lg border border-amber-100 relative">
                <div className="absolute top-0 right-0 p-2 opacity-10"><StickyNote size={32} className="text-amber-900"/></div>
                <h4 className="text-[10px] font-black text-amber-600 uppercase tracking-widest mb-2 flex items-center gap-1.5">
                  <MessageSquare size={14}/> 备注
                </h4>
                <p className="text-sm font-bold text-amber-900 leading-relaxed italic">
                  "{selectedMaker.remarks}"
                </p>
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end">
              <button onClick={() => setSelectedMaker(null)} className="px-6 py-2 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded hover:bg-slate-800 transition-colors">确认并关闭</button>
