        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
           <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => !isAiProcessing && setIsAiEditing(false)}></div>
           <div className="bg-white rounded-xl border border-slate-200 w-full max-w-lg relative overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-200">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30">
                 <div className="flex items-center gap-2">
                    <Sparkles className="text-blue-600" size={18}/>
                    <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">AI 智能属性提取</h4>
