              </div>

              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <Smartphone size={14}/> 负责业务
                </h4>
                <div className="flex flex-wrap gap-2">
                  {['推广', '预装', 'Push', '联运'].map((biz) => {
                    const isSelected = selectedMaker.responsibleBusiness?.includes(biz);
                    return (
                      <button 
                        key={biz}
                        onClick={() => toggleBusiness(biz)}
                        className={`flex items-center justify-center gap-1.5 py-1 px-2.5 rounded border transition-all font-black text-[9px] uppercase tracking-tighter
                          ${isSelected 
                            ? 'bg-slate-900 border-slate-950 text-white shadow-sm' 
                            : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'}`}
                      >
                        {isSelected ? <Check size={10}/> : <div className="w-2 h-2 border border-slate-100 rounded"></div>}
                        {biz}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <GraduationCap size={14}/> 教育背景
                </h4>
                <div className="space-y-2">
                  {selectedMaker.education && selectedMaker.education.length > 0 ? (
                    selectedMaker.education.map((edu, i) => (
                      <div key={i} className="flex items-center gap-3 p-3 bg-slate-50 rounded border border-slate-100 text-sm font-bold text-slate-800">
                        <div className="w-1.5 h-1.5 rounded-full bg-slate-400"></div>
                        {edu}
                      </div>
                    ))
                  ) : (
                    <div className="text-xs font-bold text-slate-300 italic">暂无公开教育背景记录</div>
                  )}
                </div>
              </div>

              <div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-1.5">
                  <History size={14}/> 工作履历
                </h4>
                <div className="space-y-4">
                  {selectedMaker.workExperience.map((exp, i) => (
                    <div key={i} className="flex gap-4 group">
                      <div className="w-1.5 h-1.5 rounded-full bg-slate-300 mt-1.5 shrink-0 group-hover:bg-blue-600 transition-colors"></div>
                      <div className="text-sm font-bold text-slate-700 leading-relaxed">{exp}</div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="p-6 bg-amber-50 rounded-xl border border-amber-100 relative shadow-sm">
                <div className="flex justify-between items-center mb-4">
                  <h4 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-1.5">
                    <MessageSquare size={14}/> 运营备注
                  </h4>
                  {!isEditingRemarks ? (
                    <button 
                      onClick={startEditRemarks} 
                      className="flex items-center gap-1 px-2 py-1 bg-white border border-amber-200 rounded text-[9px] font-black text-amber-600 hover:bg-amber-100 transition-all shadow-sm uppercase tracking-widest"
                    >
                      <PencilLine size={12}/> 编辑备注
                    </button>
                  ) : (
                    <button 
                      onClick={saveRemarks} 
                      className="flex items-center gap-1 px-2 py-1 bg-emerald-600 border border-emerald-700 rounded text-[9px] font-black text-white hover:bg-emerald-700 transition-all shadow-sm uppercase tracking-widest"
                    >
                      <Check size={12}/> 保存备注
                    </button>
                  )}
                </div>

                {isEditingRemarks ? (
                  <textarea
                    value={remarksText}
                    onChange={(e) => setRemarksText(e.target.value)}
                    className="w-full bg-white border border-amber-200 rounded-lg p-3 text-sm font-bold text-slate-900 focus:outline-none focus:ring-2 focus:ring-amber-300 min-h-[100px] shadow-inner"
                    autoFocus
                  />
                ) : (
                  <div className="relative">
                    <div className="absolute -left-2 -top-2 opacity-5 text-amber-900"><StickyNote size={40}/></div>
                    <p className="text-sm font-bold text-amber-900 leading-relaxed italic relative z-10">
                      "{selectedMaker.remarks || '目前该决策人暂无运营录入的备注信息。'}"
                    </p>
                  </div>
                )}
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end">
              <button 
                onClick={() => setSelectedMaker(null)} 
                className="px-8 py-3 bg-slate-900 text-white text-[11px] font-black uppercase tracking-widest rounded shadow-lg hover:bg-slate-800 transition-all flex items-center gap-2"
              >
                <Save size={14}/> 保存并关闭
              </button>
            </div>
          </div>
        </div>
      )}

      {/* AI 编辑与新增弹窗 */}
      {isAiEditing && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
           <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => !isAiProcessing && setIsAiEditing(false)}></div>
           <div className="bg-white rounded-xl border border-slate-200 w-full max-w-lg relative overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-200">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30 text-left">
                 <div className="flex items-center gap-2">
                    <Sparkles className="text-blue-600" size={18}/>
                    <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">
                        {isAddingNew ? 'AI 智能新增决策人' : 'AI 智能更新背景信息'}
                    </h4>
                 </div>
                 <button onClick={() => setIsAiEditing(false)} className="text-slate-400 hover:text-slate-600"><X size={18}/></button>
              </div>
              <div className="p-8 text-left">
                 <div className="mb-6">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">
                        {isAddingNew ? '输入一段关于新决策人的自然语言描述（姓名、职位、背景等）' : '输入最新背景动态（职位变动、负责业务变更等）'}
                    </label>
                    <textarea 
                      value={aiInputText}
                      onChange={(e) => setAiInputText(e.target.value)}
                      placeholder={isAddingNew ? "例如：新加入了一个负责人李强，担任增长总监，他来自腾讯，主要负责预装和推广业务，是个关键影响者..." : "例如：王总升职为 VP 了，现在也开始管预装业务，他是核心决策者..."}
                      className="w-full h-32 p-4 text-sm font-bold text-slate-900 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none placeholder:text-slate-300 resize-none"
                    ></textarea>
                 </div>
                 <div className="flex items-center justify-end gap-3">
                    <button 
                      onClick={() => setIsAiEditing(false)}
                      className="px-6 py-2.5 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-900 transition-colors"
                    >
                      取消
                    </button>
                    <button 
                      onClick={handleAiUpdate}
                      disabled={isAiProcessing || !aiInputText.trim()}
                      className={`px-8 py-2.5 bg-blue-600 text-white text-xs font-black uppercase tracking-widest rounded-lg shadow-lg shadow-blue-600/20 flex items-center gap-3 transition-all
                        ${isAiProcessing ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700'}`}
                    >
                      {isAiProcessing ? <Loader2 size={16} className="animate-spin"/> : <Sparkles size={16}/>}
                      {isAiProcessing ? '正在智能解析...' : '立即同步'}
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* 4. 拜访历史 */}
      <section className="bg-white rounded border border-slate-200 p-8 shadow-sm">
         {renderSectionHeader("历次拜访与遗留事项跟踪", <History size={16}/>)}
         <div className="space-y-6">
            {client.visitHistory.map(visit => (
               <div key={visit.id} className="p-6 border border-slate-100 rounded-lg bg-slate-50/30">
                  <div className="flex items-center gap-3 mb-2">
                    <span className="px-2 py-0.5 bg-slate-200 text-slate-600 text-[10px] font-black rounded">{visit.date}</span>
                    <h4 className="text-sm font-black text-slate-900">{visit.title}</h4>
                  </div>
                  <p className="text-xs font-bold text-slate-600 italic">“{visit.conclusions}”</p>
               </div>
            ))}
         </div>
      </section>

      {/* 底部 AI 分析报告按钮 */}
      <button 
        onClick={handleGenerateInsight}
        disabled={loadingInsight}
        className="fixed bottom-10 right-10 bg-slate-950 text-white px-6 py-3 rounded-full font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all border border-slate-800 shadow-2xl flex items-center gap-3 z-50"
      >
        {loadingInsight ? <Loader2 size={18} className="animate-spin"/> : <BrainCircuit size={18} className="text-white"/>}
        生成 AI 分析报告
      </button>

      {/* AI 报告模态框 */}
      {insight && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setInsight(null)}></div>
            <div className="bg-white rounded border border-slate-200 w-full max-w-2xl relative overflow-hidden flex flex-col max-h-[90vh] shadow-2xl animate-in zoom-in-95 duration-200">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50 text-left">
                    <div className="flex items-center gap-2">
                        <Sparkles className="text-blue-600" size={20}/>
                        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">AI 深度洞察</h3>
                    </div>
                    <button onClick={() => setInsight(null)} className="p-1 hover:bg-slate-200 rounded text-slate-400"><X size={20}/></button>
                </div>
                <div className="p-8 overflow-y-auto space-y-6 text-left">
                    <div className="bg-blue-50/50 p-6 rounded border border-blue-100">
                        <h4 className="text-[10px] font-black text-blue-400 uppercase mb-3 tracking-widest">执行摘要</h4>
                        <p className="text-sm text-slate-900 font-bold">{insight.summary}</p>
                    </div>
                    <div className="space-y-3">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">行动建议</h4>
                        {insight.actionItems.map((item, idx) => (
                            <div key={idx} className="flex gap-4 p-4 border border-slate-100 rounded font-bold text-sm text-slate-700">{item}</div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

