const ImageWithFallback: React.FC<{ 
  src?: string; 
  alt: string; 
  className?: string; 
  fallbackText: string;
  size?: number;
}> = ({ src, alt, className, fallbackText, size = 16 }) => {
  const [error, setError] = useState(false);
  if (error || !src) {
    return (
      <div className={`${className} bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-200 overflow-hidden`}>
        <span className="font-bold text-lg">{fallbackText.substring(0, 1).toUpperCase()}</span>
      </div>
    );
  }
  return <img src={src} alt={alt} className={className} onError={() => setError(true)} />;
};

interface ClientDetailProps {
  client: ClientProfile;
  onNavigateToApp: (appId: string) => void;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client, onNavigateToApp }) => {
  // 维护本地决策团队状态以支持拖拽、即时新增与删除
  const [localTeam, setLocalTeam] = useState<DecisionMaker[]>(client.decisionTeam);
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);

  // AI 编辑与新增相关状态
  const [isAiEditing, setIsAiEditing] = useState(false);
  const [isAddingNew, setIsAddingNew] = useState(false);
  const [aiInputText, setAiInputText] = useState("");
  const [isAiProcessing, setIsAiProcessing] = useState(false);

  // 拖拽状态
  const [draggingId, setDraggingId] = useState<string | null>(null);

  // 删除确认状态
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  // 备注手动编辑状态
  const [isEditingRemarks, setIsEditingRemarks] = useState(false);
  const [remarksText, setRemarksText] = useState("");

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const toggleBusiness = (business: string) => {
    if (!selectedMaker) return;
    const current = selectedMaker.responsibleBusiness || [];
    const next = current.includes(business) 
      ? current.filter(b => b !== business) 
      : [...current, business];

    const updatedMaker = { ...selectedMaker, responsibleBusiness: next };
    setSelectedMaker(updatedMaker);
    updateLocalTeam(updatedMaker);
  };

  const updateLocalTeam = (maker: DecisionMaker) => {
    setLocalTeam(prev => prev.map(m => m.id === maker.id ? maker : m));
  };

  const handleAiUpdate = async () => {
    if (!aiInputText.trim()) return;
    setIsAiProcessing(true);
    try {
      const result = await parseDecisionMakerEdit(aiInputText);

      if (isAddingNew) {
        const newMaker: DecisionMaker = {
          ...result,
          id: `dm-${Date.now()}`,
          department: result.department || '未知部门',
          reportsTo: undefined 
        };
        setLocalTeam(prev => [...prev, newMaker]);
        setIsAddingNew(false);
      } else if (selectedMaker) {
        const updatedMaker = { 
          ...selectedMaker, 
          ...result,
          workExperience: Array.from(new Set([...(result.workExperience || []), ...selectedMaker.workExperience])),
          education: Array.from(new Set([...(result.education || []), ...selectedMaker.education]))
        };
        setSelectedMaker(updatedMaker);
        updateLocalTeam(updatedMaker);
      }

      setAiInputText("");
      setIsAiEditing(false);
    } catch (e) {
      alert("AI 解析失败，请重试或检查内容。");
    } finally {
      setIsAiProcessing(false);
    }
  };

  const startEditRemarks = () => {
    if (!selectedMaker) return;
    setRemarksText(selectedMaker.remarks);
    setIsEditingRemarks(true);
  };

  const saveRemarks = () => {
    if (!selectedMaker) return;
    const updatedMaker = { ...selectedMaker, remarks: remarksText };
    setSelectedMaker(updatedMaker);
    updateLocalTeam(updatedMaker);
    setIsEditingRemarks(false);
  };

  const handleDeleteMaker = () => {
    if (!selectedMaker) return;
    // 删除逻辑：将该人员从团队中移除，原来汇报给该人员的人，改为汇报给 null (成为根节点)
    setLocalTeam(prev => prev
      .filter(m => m.id !== selectedMaker.id)
      .map(m => m.reportsTo === selectedMaker.id ? { ...m, reportsTo: undefined } : m)
    );
    setSelectedMaker(null);
    setShowDeleteConfirm(false);
  };

  // 拖拽逻辑实现
  const handleDragStart = (e: React.DragEvent, id: string) => {
    setDraggingId(id);
    e.dataTransfer.setData('text/plain', id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const isDescendant = (childId: string, potentialParentId: string): boolean => {
    let current = localTeam.find(m => m.id === potentialParentId);
    while (current && current.reportsTo) {
      if (current.reportsTo === childId) return true;
      current = localTeam.find(m => m.id === current?.reportsTo);
    }
    return false;
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    const sourceId = e.dataTransfer.getData('text/plain');
    setDraggingId(null);

    if (sourceId === targetId) return;

    // 防止循环引用（不能把上级拖到下级上）
    if (isDescendant(sourceId, targetId)) {
        alert("禁止循环汇报关系调整！");
        return;
    }

    setLocalTeam(prev => prev.map(m => {
      if (m.id === sourceId) {
        return { ...m, reportsTo: targetId };
      }
      return m;
    }));
  };

  const renderSectionHeader = (title: string, icon: React.ReactNode, action?: React.ReactNode) => (
    <div className="flex items-center justify-between border-b border-slate-100 pb-4 mb-6">
      <div className="flex items-center gap-3">
        <div className="text-slate-900 bg-slate-100 p-1.5 rounded">{icon}</div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">{title}</h3>
      </div>
      {action}
    </div>
  );

  const teamTree = useMemo(() => {
    const makers = localTeam;
    const roots = makers.filter(m => !m.reportsTo);
    const buildTree = (parent: DecisionMaker): any => ({
      ...parent,
      children: makers.filter(m => m.reportsTo === parent.id).map(buildTree)
    });
    return roots.map(buildTree);
  }, [localTeam]);

  const MakerNode: React.FC<{ maker: any; level: number }> = ({ maker, level }) => {
    const hasChildren = maker.children && maker.children.length > 0;
    const roleColors = {
      DECISION: 'border-slate-950 bg-white ring-4 ring-slate-950/5 shadow-xl scale-105',
      INFLUENCER: 'border-blue-600 bg-white ring-4 ring-blue-600/5',
      EXECUTION: 'border-slate-300 bg-slate-50 ring-0'
    };

    const isBeingDragged = draggingId === maker.id;

    return (
      <div className="flex flex-col items-center relative">
        <div 
          draggable
          onDragStart={(e) => handleDragStart(e, maker.id)}
          onDragOver={handleDragOver}
          onDrop={(e) => handleDrop(e, maker.id)}
          onClick={() => {
            setSelectedMaker(maker);
            setIsEditingRemarks(false);
            setShowDeleteConfirm(false);
          }}
          className={`relative z-10 w-52 p-4 rounded-lg border-2 cursor-pointer transition-all hover:shadow-2xl hover:-translate-y-1 active:scale-95 group/card 
            ${roleColors[maker.role as keyof typeof roleColors]} 
            ${isBeingDragged ? 'opacity-30 border-dashed border-blue-400' : ''}
            ${draggingId && !isBeingDragged ? 'hover:border-blue-500 hover:bg-blue-50/30' : ''}
          `}
        >
          <div className="absolute top-1 right-1 opacity-0 group-hover/card:opacity-100 text-slate-300">
            <Move size={12}/>
          </div>

          <div className="flex items-center gap-3">
            <ImageWithFallback 
               src={maker.avatar} 
               alt={maker.name} 
               fallbackText={maker.name}
               className="w-10 h-10 rounded-full shrink-0 border border-slate-100 shadow-inner"
            />
            <div className="overflow-hidden text-left">
              <div className="flex items-center gap-1.5 mb-0.5">
                <span className="text-xs font-black text-slate-900 truncate">{maker.name}</span>
              </div>
              <div className="text-[8px] font-bold text-slate-500 truncate leading-tight">{maker.title}</div>
            </div>
          </div>
        </div>
        {hasChildren && (
          <div className="flex gap-12 mt-12 relative items-start">
            <div className="absolute -top-12 left-1/2 -translate-x-1/2 w-0.5 h-12 bg-slate-200"></div>
            {maker.children.length > 1 && (
              <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-slate-200 h-0.5" 
                style={{ width: `calc(100% - ${208 / maker.children.length}px)` }}>
              </div>
            )}
            {maker.children.map((child: any) => (
              <MakerNode key={child.id} maker={child} level={level + 1} />
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300 text-left">

      {/* 1. 客户基本信息 */}
      <section className="bg-white rounded border border-slate-200 overflow-hidden shadow-sm">
         <div className="p-8 pb-0 flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
            <div className="flex items-center gap-6">
              <ImageWithFallback src={client.logo} alt={client.name} className="w-20 h-20 rounded border border-slate-100 object-cover shadow-sm" fallbackText={client.name} size={32} />
              <div>
                <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{client.name}</h1>
                <div className="flex items-center gap-3 text-xs text-slate-500 mt-2 font-bold">
                  <span className="flex items-center gap-1"><Building size={12}/> {client.industry}</span>
                  <span className={`${client.stage === ClientStage.ACTIVE ? 'text-green-600' : 'text-red-600'}`}>{client.stage === ClientStage.ACTIVE ? '活跃状态' : '风险预警'}</span>
                </div>
              </div>
            </div>
         </div>
         <div className="px-8 pb-8 pt-2 grid grid-cols-1 md:grid-cols-3 gap-6 border-t border-slate-50 mt-4 text-left">
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">公司主体</div>
                <div className="text-sm font-bold text-slate-900 truncate">{client.corporateEntity}</div>
             </div>
             <div className="pt-4">
                <div className="text-[10px] text-slate-400 mb-1 font-black uppercase tracking-widest">账户评级</div>
                <div className="flex items-center gap-1.5 text-amber-600 text-sm font-black uppercase"><Award size={14}/> {client.accountRating}</div>
             </div>
