import React, { useState } from 'react';
import { 
  BookOpen, Target, Layout, Activity, Users, 
  Coins, CheckSquare, Fingerprint, Edit2, 
  Save, X, Sparkles, Loader2, ChevronDown, ChevronUp, History as HistoryIcon
} from 'lucide-react';
import { CorporateBasicInfo, InfoCategory } from '../../types';

interface CorporateBasicInfoCardProps {
  data: CorporateBasicInfo;
  onUpdate: (newData: CorporateBasicInfo) => void;
  onAiUpdate: (inputText: string) => Promise<void>;
  isAiProcessing: boolean;
}

const SECTION_CONFIG = [
  { key: 'history', label: '发展历程', icon: <BookOpen size={16}/> },
  { key: 'strategy', label: '战略规划', icon: <Target size={16}/> },
  { key: 'productLayout', label: '产品布局', icon: <Layout size={16}/> },
  { key: 'businessStatus', label: '经营情况', icon: <Activity size={16}/> },
  { key: 'orgStructure', label: '组织架构', icon: <Users size={16}/> },
  { key: 'budgetAllocation', label: '预算分配', icon: <Coins size={16}/> },
  { key: 'evaluationMethod', label: '考核方式', icon: <CheckSquare size={16}/> },
  { key: 'attributionMethod', label: '归因方式', icon: <Fingerprint size={16}/> },
] as const;

export const CorporateBasicInfoCard: React.FC<CorporateBasicInfoCardProps> = ({ 
  data, onUpdate, onAiUpdate, isAiProcessing 
}) => {
  const [editingKey, setEditingKey] = useState<string | null>(null);
  const [tempText, setTempText] = useState("");
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiInput, setAiInput] = useState("");
  const [expandedHistories, setExpandedHistories] = useState<Record<string, boolean>>({});

  const toggleHistory = (key: string) => {
    setExpandedHistories(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleEdit = (key: string, currentVal: string) => {
    setEditingKey(key);
    setTempText(currentVal);
  };

  const handleSave = () => {
    if (editingKey) {
      const category = data[editingKey as keyof CorporateBasicInfo] as InfoCategory;
      const newEntry = {
        id: `entry-${Date.now()}`,
        date: new Date().toISOString().split('T')[0],
        content: tempText
      };

      onUpdate({ 
        ...data, 
        [editingKey]: {
          ...category,
          summary: tempText,
          history: [newEntry, ...(category.history || [])]
        } 
      });
      setEditingKey(null);
    }
  };

  const handleAiSubmit = async () => {
    if (!aiInput.trim()) return;
    await onAiUpdate(aiInput);
    setAiInput("");
    setShowAiModal(false);
  };

  return (
    <section className="bg-white rounded border border-slate-200 p-8 shadow-sm text-left">
      <div className="flex items-center justify-between border-b border-slate-100 pb-4 mb-8">
        <div className="flex items-center gap-3">
          <div className="text-slate-900 bg-slate-100 p-1.5 rounded"><BookOpen size={16}/></div>
          <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">客户基本情况</h3>
        </div>
        <button 
          onClick={() => setShowAiModal(true)}
          className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 text-white rounded text-[10px] font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg active:scale-95"
        >
          <Sparkles size={14}/> 更新信息 (AI)
        </button>
      </div>

      <div className="space-y-6">
        {SECTION_CONFIG.map((section) => {
          const isEditing = editingKey === section.key;
          const category = data[section.key as keyof CorporateBasicInfo] as InfoCategory;
          const summary = category?.summary || "暂无综述";
          const history = category?.history || [];
          const isExpanded = expandedHistories[section.key];

          return (
            <div key={section.key} className="border border-slate-100 rounded-lg overflow-hidden bg-slate-50/20 hover:border-slate-200 transition-all">
              {/* 头部区域 */}
              <div className="flex items-center justify-between p-4 bg-slate-50/50 border-b border-slate-100">
                <div className="flex items-center gap-3">
                  <span className="text-blue-600">{section.icon}</span>
                  <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest">{section.label}</span>
                </div>
                <div className="flex items-center gap-2">
                  <button 
                    onClick={() => toggleHistory(section.key)}
                    className="flex items-center gap-1.5 px-2 py-1 hover:bg-slate-200 rounded text-[9px] font-black text-slate-400 uppercase transition-all"
                  >
                    <HistoryIcon size={12}/>
                    {history.length} 条记录
                    {isExpanded ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
                  </button>
                  {!isEditing && (
                    <button 
                      onClick={() => handleEdit(section.key, summary)}
                      className="p-1.5 hover:bg-slate-200 rounded text-slate-400 transition-all"
                    >
                      <Edit2 size={12}/>
                    </button>
                  )}
                </div>
              </div>

              {/* 内容综述区域 */}
              <div className="p-5">
                {isEditing ? (
                  <div className="space-y-3">
                    <textarea 
                      value={tempText}
                      onChange={(e) => setTempText(e.target.value)}
                      className="w-full text-sm font-bold p-3 border border-blue-200 rounded bg-white min-h-[100px] focus:ring-2 focus:ring-blue-500 outline-none shadow-inner"
                      autoFocus
                    />
                    <div className="flex justify-end gap-2">
                      <button onClick={() => setEditingKey(null)} className="px-3 py-1.5 text-[10px] font-black uppercase text-slate-400 hover:text-slate-900 transition-colors">取消</button>
                      <button onClick={handleSave} className="flex items-center gap-2 px-4 py-1.5 bg-blue-600 text-white rounded text-[10px] font-black uppercase hover:bg-blue-700 shadow-md"><Save size={12}/> 保存并更新</button>
                    </div>
                  </div>
                ) : (
                  <div className="relative">
                    <div className="text-[10px] font-black text-slate-300 uppercase mb-2 tracking-tighter">当前综述 (Summary)</div>
                    <p className="text-sm font-bold text-slate-700 leading-relaxed border-l-2 border-blue-100 pl-4">
                      {summary}
                    </p>
                  </div>
                )}
              </div>

              {/* 历史记录列表 */}
              {isExpanded && (
                <div className="px-5 pb-5 bg-white/50 animate-in slide-in-from-top-2 duration-200">
                  <div className="text-[10px] font-black text-slate-300 uppercase mb-3 border-t border-slate-50 pt-4 tracking-tighter">变更历史 (History)</div>
                  <div className="space-y-4">
                    {history.length > 0 ? (
                      history.map((entry) => (
                        <div key={entry.id} className="relative pl-6 before:content-[''] before:absolute before:left-0 before:top-2 before:w-1.5 before:h-1.5 before:bg-slate-200 before:rounded-full after:content-[''] after:absolute after:left-[2px] after:top-4 after:bottom-[-1rem] after:w-[1px] after:bg-slate-100 last:after:hidden">
                          <div className="text-[9px] font-black text-slate-400 uppercase mb-1">{entry.date}</div>
                          <p className="text-xs font-bold text-slate-500 leading-relaxed">{entry.content}</p>
                        </div>
                      ))
                    ) : (
                      <div className="text-[10px] font-bold text-slate-300 italic">暂无历史记录</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* AI 录入弹窗 */}
      {showAiModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => !isAiProcessing && setShowAiModal(false)}></div>
          <div className="bg-white rounded-xl border border-slate-200 w-full max-w-lg relative overflow-hidden shadow-2xl p-8 animate-in fade-in zoom-in-95 duration-200">
            <div className="flex items-center gap-2 mb-6">
              <Sparkles className="text-blue-600" size={18}/>
              <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">AI 客户背景更新</h4>
            </div>
            <p className="text-[10px] font-black text-slate-400 uppercase mb-4 leading-relaxed">
              AI 将根据您的输入，自动生成新的综述并追加至各子项的变更历史中。
            </p>
            <textarea 
              value={aiInput} 
              onChange={(e) => setAiInput(e.target.value)}
              placeholder="粘贴最新的市场动态、会议纪要或战略调整说明..."
              className="w-full h-48 p-4 text-sm font-bold border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 bg-slate-50"
              disabled={isAiProcessing}
            />
            <div className="flex justify-end gap-3">
              <button 
                onClick={() => setShowAiModal(false)} 
                disabled={isAiProcessing}
                className="px-6 py-2.5 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-900"
              >
                取消
              </button>
              <button 
                onClick={handleAiSubmit} 
                disabled={isAiProcessing || !aiInput.trim()} 
                className="px-8 py-2.5 bg-blue-600 text-white text-xs font-black uppercase tracking-widest rounded-lg flex items-center gap-3 hover:bg-blue-700 shadow-lg shadow-blue-500/20 disabled:opacity-50"
              >
                {isAiProcessing ? <Loader2 size={16} className="animate-spin"/> : <Sparkles size={16}/>} 立即解析并同步
              </button>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

import React, { useState, useCallback } from 'react';
import { 
  BrainCircuit, Loader2, History, AlertCircle, Sparkles, X 
} from 'lucide-react';
import { ClientProfile, InsightResponse, DecisionMaker, CorporateBasicInfo, InfoCategory } from '../types';
import { generateClientInsight, parseDecisionMakerEdit, extractCorporateBasicInfo } from '../services/geminiService';

// 导入拆分后的原子组件
import { ClientBasicInfoCard } from './client/ClientBasicInfoCard';
import { OrgChartCard } from './client/OrgChartCard';
import { DecisionMakerModal } from './client/DecisionMakerModal';
import { AiInsightModal } from './client/AiInsightModal';
import { AppMatrixCard } from './client/AppMatrixCard';
import { FinancialPerformanceCard } from './client/FinancialPerformanceCard';
import { VisitHistoryCard } from './client/VisitHistoryCard';
import { ClientDynamicsCard } from './client/ClientDynamicsCard';
import { CorporateBasicInfoCard } from './client/CorporateBasicInfoCard';

interface ClientDetailProps {
  client: ClientProfile;
  onNavigateToApp: (appId: string) => void;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client, onNavigateToApp }) => {
  const [localTeam, setLocalTeam] = useState<DecisionMaker[]>(client.decisionTeam);
  const [localBasicInfo, setLocalBasicInfo] = useState<CorporateBasicInfo>(client.corporateBasicInfo);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  // AI 更新/新增状态
  const [isAiEditing, setIsAiEditing] = useState(false);
  const [isAddingNew, setIsAddingNew] = useState(false);
  const [aiInputText, setAiInputText] = useState("");
  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const [isAiBasicInfoProcessing, setIsAiBasicInfoProcessing] = useState(false);

  // 备注编辑状态
  const [isEditingRemarks, setIsEditingRemarks] = useState(false);
  const [remarksText, setRemarksText] = useState("");
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [draggingId, setDraggingId] = useState<string | null>(null);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) { console.error(e); } finally { setLoadingInsight(false); }
  };

  const handleDrop = useCallback((sourceId: string, targetId: string) => {
    if (sourceId === targetId) return;
    setLocalTeam(prev => prev.map(m => m.id === sourceId ? { ...m, reportsTo: targetId } : m));
  }, []);

  const handleAiUpdateMaker = async () => {
    if (!aiInputText.trim()) return;
    setIsAiProcessing(true);
    try {
      const result = await parseDecisionMakerEdit(aiInputText);
      if (isAddingNew) {
        const newMaker: DecisionMaker = { ...result, id: `dm-${Date.now()}`, department: result.department || '未知' };
        setLocalTeam(prev => [...prev, newMaker]);
        setIsAddingNew(false);
      } else if (selectedMaker) {
        const updated = { ...selectedMaker, ...result };
        setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
        setSelectedMaker(updated);
      }
      setAiInputText(""); setIsAiEditing(false);
    } catch (e) { alert("AI 解析失败"); } finally { setIsAiProcessing(false); }
  };

  const handleAiUpdateBasicInfo = async (inputText: string) => {
    setIsAiBasicInfoProcessing(true);
    try {
      const result = await extractCorporateBasicInfo(inputText);
      const today = new Date().toISOString().split('T')[0];

      const newBasicInfo = { ...localBasicInfo };

      // 遍历所有键进行智能合并与历史追加
      Object.keys(result).forEach((key) => {
        const fieldKey = key as keyof CorporateBasicInfo;
        const newContent = result[key];

        if (newContent && newContent.trim()) {
          const currentCategory = localBasicInfo[fieldKey] || { summary: '', history: [] };
          const newEntry = {
            id: `ai-${Date.now()}-${fieldKey}`,
            date: today,
            content: newContent
          };

          newBasicInfo[fieldKey] = {
            summary: newContent,
            history: [newEntry, ...(currentCategory.history || [])]
          };
        }
      });

      setLocalBasicInfo(newBasicInfo);
    } catch (e) {
      alert("AI 背景解析失败，请检查网络或重试。");
    } finally {
      setIsAiBasicInfoProcessing(false);
    }
  };

  const toggleBusiness = (biz: string) => {
    if (!selectedMaker) return;
    const current = selectedMaker.responsibleBusiness || [];
    const next = current.includes(biz) ? current.filter(b => b !== biz) : [...current, biz];
    const updated = { ...selectedMaker, responsibleBusiness: next };
    setSelectedMaker(updated);
    setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300 text-left">
      {/* 基本信息头部 */}
      <ClientBasicInfoCard client={client} />

      {/* 财务表现 */}
      <FinancialPerformanceCard client={client} />

      {/* 客户基本情况卡片 (重构为垂直布局) */}
      <CorporateBasicInfoCard 
        data={localBasicInfo} 
        onUpdate={setLocalBasicInfo}
        onAiUpdate={handleAiUpdateBasicInfo}
        isAiProcessing={isAiBasicInfoProcessing}
      />

      {/* App 矩阵 */}
      <AppMatrixCard matrix={client.appMatrix} onNavigate={onNavigateToApp} />

      {/* 组织图谱 */}
      <OrgChartCard 
        localTeam={localTeam}
        onAddClick={() => { setIsAddingNew(true); setIsAiEditing(true); }}
        onMakerClick={(m) => { setSelectedMaker(m); setIsEditingRemarks(false); }}
        onDrop={handleDrop}
        draggingId={draggingId}
        setDraggingId={setDraggingId}
      />

      {/* 实时动态 */}
      <ClientDynamicsCard dynamics={client.dynamics} />

      {/* 拜访记录 */}
      <VisitHistoryCard history={client.visitHistory} />

      {/* 模态框组 */}
      {selectedMaker && (
        <DecisionMakerModal 
          maker={selectedMaker}
          onClose={() => setSelectedMaker(null)}
          onAiEditClick={() => { setIsAddingNew(false); setIsAiEditing(true); }}
          onToggleBusiness={toggleBusiness}
          isEditingRemarks={isEditingRemarks}
          remarksText={remarksText}
          setRemarksText={setRemarksText}
          onStartEditRemarks={() => { setRemarksText(selectedMaker.remarks); setIsEditingRemarks(true); }}
          onSaveRemarks={() => {
            const updated = { ...selectedMaker, remarks: remarksText };
            setSelectedMaker(updated);
            setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
            setIsEditingRemarks(false);
          }}
          onDeleteClick={() => setShowDeleteConfirm(true)}
        />
      )}

      {showDeleteConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => setShowDeleteConfirm(false)}></div>
          <div className="bg-white rounded-xl border border-slate-200 w-full max-w-sm relative overflow-hidden shadow-2xl p-8 text-center">
            <div className="w-16 h-16 bg-rose-50 text-rose-600 rounded-full flex items-center justify-center mx-auto mb-6"><AlertCircle size={32}/></div>
            <h4 className="text-lg font-black text-slate-900 mb-2">确认删除？</h4>
            <div className="flex gap-4 mt-8">
              <button onClick={() => setShowDeleteConfirm(false)} className="flex-1 px-4 py-3 border border-slate-200 text-slate-600 text-[10px] font-black uppercase tracking-widest rounded-lg">取消</button>
              <button onClick={() => {
                setLocalTeam(prev => prev.filter(m => m.id !== selectedMaker?.id));
                setSelectedMaker(null); setShowDeleteConfirm(false);
              }} className="flex-1 px-4 py-3 bg-rose-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg">确认删除</button>
            </div>
          </div>
        </div>
      )}

      {isAiEditing && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => !isAiProcessing && setIsAiEditing(false)}></div>
          <div className="bg-white rounded-xl border border-slate-200 w-full max-w-lg relative overflow-hidden shadow-2xl animate-in fade-in duration-200 p-8 text-left text-slate-900">
            <div className="flex items-center gap-2 mb-6">
              <Sparkles className="text-blue-600" size={18}/>
              <h4 className="text-xs font-black uppercase tracking-widest">{isAddingNew ? 'AI 智能新增' : 'AI 更新背景'}</h4>
            </div>
            <textarea 
              value={aiInputText} onChange={(e) => setAiInputText(e.target.value)}
              placeholder="输入描述信息..."
              className="w-full h-32 p-4 text-sm font-bold border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 bg-white"
            />
