import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse, CorporateWiki, AppIntelligence, DynamicInfo, InfoHistoryEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * 基于历史记录生成该维度的综述总结
 */
export const summarizeCategoryHistory = async (categoryName: string, history: InfoHistoryEntry[]): Promise<string> => {
  if (history.length === 0) return "";

  const historyText = history.map(h => `[${h.date}] ${h.content}`).join('\n');
  const prompt = `
    你是一个资深的商业分析师。请针对客户基本情况中的“${categoryName}”维度，根据以下按时间排序的变更记录，总结出一份精炼、专业的现状综述。

    变更记录：
    ${historyText}

    输出要求：
    - 语言专业、简练（100字以内）。
    - 重点突出最新的变化和当前的核心状态。
    - 不要包含“综述如下”等废话，直接输出内容。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "";
  } catch (e) {
    console.error("AI Summarization Error:", e);
    return history[0].content; // 降级处理：返回最新的一条记录内容
  }
};

/**
 * 从原始文本提取 8 个维度的客户基本信息
 */
export const extractCorporateBasicInfo = async (inputText: string): Promise<any> => {
  const prompt = `
    你是一个资深的商业分析师。请分析以下关于某广告主客户的描述文本，并将其提取为 8 个关键维度的结构化信息。
    描述文本：“${inputText}”

    提取维度：
    1. 发展历程 (history)
    2. 战略规划 (strategy)
    3. 产品布局 (productLayout)
    4. 经营情况 (businessStatus)
    5. 组织架构 (orgStructure)
    6. 预算分配 (budgetAllocation)
    7. 考核方式 (evaluationMethod)
    8. 归因方式 (attributionMethod)

    输出要求：
    - 严格的 JSON 格式。
    - 如果文本中未提到某个维度，请在该字段填入空字符串。
    - 语言简洁、专业。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            history: { type: Type.STRING },
            strategy: { type: Type.STRING },
            productLayout: { type: Type.STRING },
            businessStatus: { type: Type.STRING },
            orgStructure: { type: Type.STRING },
            budgetAllocation: { type: Type.STRING },
            evaluationMethod: { type: Type.STRING },
            attributionMethod: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    console.error("AI Basic Info Extraction Error:", e);
    throw e;
  }
};

/**
 * AI 解析非结构化文本，更新或新增决策人字段
 */
export const parseDecisionMakerEdit = async (inputText: string): Promise<any> => {
  const prompt = `
    你是一个专业的数据抓取助手。请解析以下关于某公司决策人的描述文本，提取关键字段信息：
    描述文本：“${inputText}”

    提取规则：
    1. 姓名 (name): 提取人名。
    2. 职位 (title): 提取其最新职衔。
    3. 部门 (department): 提取所属部门。
    4. 角色 (role): 根据重要性判断为 "DECISION" (决策), "INFLUENCER" (建议者), "EXECUTION" (执行者)。
    5. 决策力 (decisionPower): 判断为 "HIGH" (高), "MEDIUM" (中), "LOW" (低)。默认 "MEDIUM"。
    6. 联系方式 (contact): 提取邮箱或电话。
    7. 负责业务 (responsibleBusiness): 仅从以下选项中选择（可多选）："推广", "预装", "Push", "联运"。
    8. 工作履历 (workExperience): 返回字符串数组。
    9. 教育背景 (education): 返回字符串数组。
    10. 备注 (remarks): 运营关注点。

    输出要求：严格的 JSON 格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            title: { type: Type.STRING },
            department: { type: Type.STRING },
            role: { type: Type.STRING, enum: ['DECISION', 'INFLUENCER', 'EXECUTION'] },
            decisionPower: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] },
            contact: { type: Type.STRING },
            responsibleBusiness: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING, enum: ['推广', '预装', 'Push', '联运'] } 
            },
            workExperience: { type: Type.ARRAY, items: { type: Type.STRING } },
            education: { type: Type.ARRAY, items: { type: Type.STRING } },
            remarks: { type: Type.STRING }
          },
          required: ['name', 'title', 'role', 'decisionPower', 'responsibleBusiness', 'workExperience', 'education', 'remarks']
        }
      }
    });

    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    console.error("AI Parse Error:", e);
    throw e;
  }
};

/**
 * 从会议纪要文本中提取会谈要点和遗留问题
 */
export const extractMeetingMinutes = async (minutesText: string): Promise<{ mainContent: string, issues: { description: string, owner: string }[] }> => {
  const prompt = `
    你是一个专业的会议秘书。请分析以下会议纪要文本，提取核心的“会谈要点”和“遗留问题”（Action Items）。

    会议纪要：
    “${minutesText}”

    提取规则：
    1. 会谈要点 (mainContent): 总结会议的核心讨论内容、达成的共识或关键信息。语言简练专业。
    2. 遗留问题 (issues): 提取所有需要后续跟进的任务。
       - 描述 (description): 任务的具体内容。
       - 责任人 (owner): 任务的负责人。如果文中未明确提及，请留空字符串。

    输出格式：
    请返回严格的 JSON 格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            mainContent: { type: Type.STRING },
            issues: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  description: { type: Type.STRING },
                  owner: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });
    return JSON.parse(response.text?.trim() || '{"mainContent": "", "issues": []}');
  } catch (e) {
    console.error("AI Meeting Minutes Extraction Error:", e);
    // Fallback: use raw text as content
    return { mainContent: minutesText, issues: [] };
  }
};

/**
 * 抓取公司全网实时新闻与动态
 */
export const fetchCompanyNews = async (companyName: string): Promise<DynamicInfo[]> => {
  const prompt = `搜索并汇总关于“${companyName}”公司的最新实时动态（过去 30 天内）。输出 JSON。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json'
      }
    });
    return JSON.parse(response.text?.trim() || '[]');
  } catch (e) {
    return [];
  }
};

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const prompt = `分析广告主 ${client.name} 的数据。输出 JSON：summary, actionItems, prediction。`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });
    return JSON.parse(response.text?.trim() || '{}');
  } catch (e) {
    return { summary: "不可用", actionItems: [] };
  }
};

import React, { useState } from 'react';
import { 
  History, 
  MapPin, 
  Users, 
  FileText, 
  ClipboardList, 
  CheckCircle2, 
  Clock, 
  Edit3, 
  Save, 
  X,
  UserCheck,
  UserPlus,
  AlertCircle,
  PlusCircle,
  Calendar,
  MessageSquare,
  Milestone,
  Trash2,
  Sparkles,
  Loader2
} from 'lucide-react';
import { VisitRecord, IssueItem, ItineraryNode } from '../../types';
import { extractMeetingMinutes } from '../../services/geminiService';

interface VisitHistoryCardProps {
  history: VisitRecord[];
}

export const VisitHistoryCard: React.FC<VisitHistoryCardProps> = ({ history: initialHistory }) => {
  const [records, setRecords] = useState<VisitRecord[]>(initialHistory);
  const [editingIssue, setEditingIssue] = useState<{visitId: string, issueId: string} | null>(null);
  const [tempIssue, setTempIssue] = useState<Partial<IssueItem>>({});
  const [error, setError] = useState<string | null>(null);

  // 新建会晤弹窗相关状态
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newVisit, setNewVisit] = useState<Partial<VisitRecord>>({
    date: new Date().toISOString().split('T')[0],
    title: '',
    location: '',
    internalParticipants: [],
    clientParticipants: [],
    clientDemands: '',
    internalDemands: '',
    mainContent: '',
    conclusions: '',
    itinerary: []
  });

  // 会议纪要录入 AI 提取相关状态
  const [minutesModal, setMinutesModal] = useState<{ isOpen: boolean, visitId: string | null, text: string }>({ isOpen: false, visitId: null, text: '' });
  const [isExtractingMinutes, setIsExtractingMinutes] = useState(false);

  // 遗留问题删除确认
  const [deleteConfirm, setDeleteConfirm] = useState<{ isOpen: boolean, visitId: string, issueId: string } | null>(null);

  // 用于输入参与者的临时状态
  const [internalInput, setInternalInput] = useState('');
  const [clientInput, setClientInput] = useState('');

  const handleEditClick = (visitId: string, issue: IssueItem) => {
    setEditingIssue({ visitId, issueId: issue.id });
    setTempIssue(issue);
    setError(null);
  };

  const handleSaveIssue = (visitId: string) => {
    if (tempIssue.status === 'CLOSED' && (!tempIssue.progress || !tempIssue.progress.trim())) {
      setError("状态为‘已关闭’时，必须提供最新进展。");
      return;
    }

    setRecords(prev => prev.map(visit => {
      if (visit.id !== visitId) return visit;
      return {
        ...visit,
        items: visit.items.map(item => item.id === editingIssue?.issueId ? { ...item, ...tempIssue } as IssueItem : item)
      };
    }));
    setEditingIssue(null);
    setError(null);
  };

  const handleDeleteIssueClick = (visitId: string, issueId: string) => {
    setDeleteConfirm({ isOpen: true, visitId, issueId });
  };

  const confirmDeleteIssue = () => {
    if (!deleteConfirm) return;
    setRecords(prev => prev.map(visit => {
      if (visit.id !== deleteConfirm.visitId) return visit;
      return {
        ...visit,
        items: visit.items.filter(item => item.id !== deleteConfirm.issueId)
      };
    }));
    setDeleteConfirm(null);
  };

  const handleCreateVisit = () => {
    if (!newVisit.title || !newVisit.date) {
      alert("请填写会晤标题和日期");
      return;
    }
    const visitToSave: VisitRecord = {
      ...newVisit as VisitRecord,
      id: `v-${Date.now()}`,
      items: [], // 留空
      conclusions: newVisit.conclusions || '暂无结论'
    };
    setRecords(prev => [visitToSave, ...prev]);
    setShowCreateModal(false);
    // 重置
    setNewVisit({
      date: new Date().toISOString().split('T')[0],
      title: '', location: '', internalParticipants: [], clientParticipants: [],
      clientDemands: '', internalDemands: '', mainContent: '', conclusions: '', itinerary: []
    });
  };

  const addItineraryNode = () => {
    const newNode: ItineraryNode = {
      id: `it-${Date.now()}`,
      date: newVisit.date || '',
      time: '09:00',
      content: ''
    };
    setNewVisit(prev => ({ ...prev, itinerary: [...(prev.itinerary || []), newNode] }));
  };

  const removeItineraryNode = (id: string) => {
    setNewVisit(prev => ({ ...prev, itinerary: (prev.itinerary || []).filter(n => n.id !== id) }));
  };

  const updateItineraryNode = (id: string, field: keyof ItineraryNode, value: string) => {
    setNewVisit(prev => ({
      ...prev,
      itinerary: (prev.itinerary || []).map(n => n.id === id ? { ...n, [field]: value } : n)
    }));
  };

  const handleOpenMinutesModal = (visitId: string) => {
    setMinutesModal({ isOpen: true, visitId, text: '' });
  };

  const handleAnalyzeMinutes = async () => {
    if (!minutesModal.visitId || !minutesModal.text.trim()) return;
    setIsExtractingMinutes(true);
    try {
      const result = await extractMeetingMinutes(minutesModal.text);

      setRecords(prev => prev.map(visit => {
        if (visit.id !== minutesModal.visitId) return visit;

        // 生成新的遗留问题
        const newIssues: IssueItem[] = result.issues.map((issue, idx) => ({
          id: `ai-issue-${Date.now()}-${idx}`,
          description: issue.description,
          owner: issue.owner || '待确认',
          status: 'IN_PROGRESS',
          progress: '会议纪要自动提取'
        }));

        return {
          ...visit,
          mainContent: result.mainContent || visit.mainContent, // 优先使用提取的总结
          items: [...visit.items, ...newIssues]
        };
      }));
      setMinutesModal({ isOpen: false, visitId: null, text: '' });
    } catch (e) {
