interface ClientBasicInfoCardProps {
  client: ClientProfile;
  onClientUpdate: (updatedClient: ClientProfile) => void;
}

export const ClientBasicInfoCard: React.FC<ClientBasicInfoCardProps> = ({ client, onClientUpdate }) => {
  const [isEditing, setIsEditing] = useState(false);

  // Local state for edits
  const [editTier, setEditTier] = useState(client.tier);
  const [editCooperation, setEditCooperation] = useState(client.cooperation);
  const [editFinancials, setEditFinancials] = useState(client.financials);

  const handleSave = () => {
    onClientUpdate({
      ...client,
      tier: editTier,
      cooperation: editCooperation,
      financials: editFinancials
    });
    setIsEditing(false);
  };

  const handleCancel = () => {
    setEditTier(client.tier);
    setEditCooperation(client.cooperation);
    setEditFinancials(client.financials);
    setIsEditing(false);
  };

  const toggleCooperation = (key: keyof typeof editCooperation) => {
    setEditCooperation(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const updateBudget = (key: keyof typeof editFinancials, value: string) => {
    const numValue = parseFloat(value);
    setEditFinancials(prev => ({
      ...prev,
      [key]: isNaN(numValue) ? 0 : numValue
    }));
  };

  const cooperationConfig = [
    { key: 'promotion', label: '推广' },
    { key: 'preinstall', label: '预装' },
    { key: 'push', label: 'Push' },
    { key: 'joint', label: '联运' },
  ] as const;

  const formatBudget = (val: number) => `¥${(val / 1000000).toFixed(1)}M`;

  return (
    <section className="bg-white rounded border border-slate-200 overflow-hidden shadow-sm relative">
      <div className="absolute top-6 right-6 z-10">
        {!isEditing ? (
          <button 
            onClick={() => setIsEditing(true)} 
            className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded text-[10px] font-black text-slate-500 uppercase tracking-widest transition-all"
          >
            <Edit3 size={12}/> 编辑信息
          </button>
        ) : (
          <div className="flex gap-2">
            <button 
              onClick={handleCancel} 
              className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-slate-200 rounded text-[10px] font-black text-slate-500 uppercase tracking-widest hover:text-slate-900 transition-all"
            >
              <X size={12}/> 取消
            </button>
            <button 
              onClick={handleSave} 
              className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 border border-blue-600 rounded text-[10px] font-black text-white uppercase tracking-widest hover:bg-blue-700 transition-all shadow-md"
            >
              <Check size={12}/> 保存
            </button>
          </div>
        )}
      </div>

      <div className="p-8 pb-0 flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
        <div className="flex items-center gap-6">
          <ImageWithFallback 
            src={client.logo} 
            alt={client.name} 
            className="w-20 h-20 rounded border border-slate-100 object-cover shadow-sm" 
            fallbackText={client.name} 
          />
          <div>
            <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight mb-3">{client.name}</h1>

            {/* 合作业务 */}
            <div className="flex flex-wrap gap-2">
              {cooperationConfig.map((item) => {
                const isActive = isEditing ? editCooperation[item.key] : client.cooperation[item.key];

                if (isEditing) {
                  return (
                    <button
                      key={item.key}
                      onClick={() => toggleCooperation(item.key)}
                      className={`px-3 py-1 rounded text-[10px] font-black uppercase tracking-widest border transition-all ${
                        isActive 
                        ? 'bg-blue-600 text-white border-blue-600' 
                        : 'bg-slate-50 text-slate-400 border-slate-200 hover:border-slate-300'
                      }`}
                    >
                      {item.label}
                    </button>
                  );
                }

                return (
                  <div 
                    key={item.key}
                    className={`px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-widest border flex items-center gap-1.5 ${
                      isActive 
                        ? 'bg-blue-50 text-blue-700 border-blue-100' 
                        : 'bg-slate-50 text-slate-300 border-slate-100 grayscale opacity-60'
                    }`}
                  >
                    <Zap size={10} className={isActive ? 'fill-blue-600 text-blue-600' : 'text-slate-300'}/>
                    {item.label}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      <div className="px-8 pb-8 pt-6 grid grid-cols-1 md:grid-cols-5 gap-8 border-t border-slate-50 mt-4 text-left">
        {/* 客户等级 */}
        <div className="md:col-span-1 border-r border-slate-100 pr-8">
          <div className="text-[10px] text-slate-400 mb-2 font-black uppercase tracking-widest flex items-center gap-1.5">
             <Award size={12}/> 客户等级
          </div>
          {isEditing ? (
            <select 
              value={editTier} 
              onChange={(e) => setEditTier(e.target.value as any)}
              className="w-full text-lg font-black text-slate-900 p-2 border border-slate-200 rounded bg-white outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="S">S 级 (战略)</option>
              <option value="A">A 级 (核心)</option>
              <option value="B">B 级 (潜力)</option>
              <option value="C">C 级 (普通)</option>
            </select>
          ) : (
            <div className={`inline-flex items-center justify-center w-12 h-12 rounded-lg text-2xl font-black shadow-sm ${
              client.tier === 'S' ? 'bg-amber-50 text-amber-600 border border-amber-100' : 
              client.tier === 'A' ? 'bg-blue-50 text-blue-600 border border-blue-100' : 
              'bg-slate-50 text-slate-500 border border-slate-100'
            }`}>
              {client.tier}
            </div>
          )}
        </div>

        {/* 预算拆分展示 */}
        <div className="md:col-span-4 grid grid-cols-2 md:grid-cols-4 gap-6">
          {[
            { label: '推广预算', key: 'promotionBudget', color: 'text-blue-600' },
            { label: '预装预算', key: 'preinstallBudget', color: 'text-emerald-600' },
            { label: 'Push预算', key: 'pushBudget', color: 'text-purple-600' },
            { label: '联运预算', key: 'jointBudget', color: 'text-orange-600' },
          ].map((budget) => {
             const key = budget.key as keyof typeof editFinancials;
             const val = isEditing ? editFinancials[key] : client.financials[key];

             return (
               <div key={budget.key} className="relative group">
                 <div className="text-[10px] text-slate-400 mb-2 font-black uppercase tracking-widest flex items-center gap-1.5">
                    <Coins size={12}/> {budget.label}
                 </div>
                 {isEditing ? (
                   <div className="relative">
                     <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs">¥</span>
                     <input 
                       type="number"
                       value={val}
                       onChange={(e) => updateBudget(key, e.target.value)}
                       className="w-full pl-6 pr-2 py-2 text-sm font-bold border border-slate-200 rounded outline-none focus:ring-2 focus:ring-blue-500"
                     />
                   </div>
                 ) : (
                   <div className={`text-lg font-black ${budget.color} tracking-tight`}>
                     {formatBudget(val as number)}
                   </div>
                 )}
               </div>
             );
          })}
        </div>
      </div>
    </section>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { 
  BrainCircuit, Loader2, History, AlertCircle, Sparkles, X 
} from 'lucide-react';
import { ClientProfile, InsightResponse, DecisionMaker, CorporateBasicInfo, InfoCategory } from '../types';
import { generateClientInsight, parseDecisionMakerEdit, extractCorporateBasicInfo, summarizeCategoryHistory } from '../services/geminiService';

// 导入拆分后的原子组件
import { ClientBasicInfoCard } from './client/ClientBasicInfoCard';
import { OrgChartCard } from './client/OrgChartCard';
import { DecisionMakerModal } from './client/DecisionMakerModal';
import { AiInsightModal } from './client/AiInsightModal';
import { AppMatrixCard } from './client/AppMatrixCard';
import { FinancialPerformanceCard } from './client/FinancialPerformanceCard';
import { VisitHistoryCard } from './client/VisitHistoryCard';
import { ClientDynamicsCard } from './client/ClientDynamicsCard';
import { CorporateBasicInfoCard } from './client/CorporateBasicInfoCard';

interface ClientDetailProps {
  client: ClientProfile;
  onNavigateToApp: (appId: string) => void;
}

const SECTION_LABELS: Record<string, string> = {
  history: '发展历程',
  strategy: '战略规划',
  productLayout: '产品布局',
  businessStatus: '经营情况',
  orgStructure: '组织架构',
  budgetAllocation: '预算分配',
  evaluationMethod: '考核方式',
  attributionMethod: '归因方式'
};

export const ClientDetail: React.FC<ClientDetailProps> = ({ client: initialClient, onNavigateToApp }) => {
  // Client state to support top-level edits
  const [clientData, setClientData] = useState<ClientProfile>(initialClient);

  // Sync prop changes to state (if switching clients)
  useEffect(() => {
    setClientData(initialClient);
  }, [initialClient]);

  const [localTeam, setLocalTeam] = useState<DecisionMaker[]>(initialClient.decisionTeam);
  const [localBasicInfo, setLocalBasicInfo] = useState<CorporateBasicInfo>(initialClient.corporateBasicInfo);
  const [selectedMaker, setSelectedMaker] = useState<DecisionMaker | null>(null);
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  // Update localTeam when clientData changes (switching clients)
  useEffect(() => {
    setLocalTeam(clientData.decisionTeam);
    setLocalBasicInfo(clientData.corporateBasicInfo);
  }, [clientData.id]);

  // AI 更新/新增状态
  const [isAiEditing, setIsAiEditing] = useState(false);
  const [isAddingNew, setIsAddingNew] = useState(false);
  const [aiInputText, setAiInputText] = useState("");
  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const [isAiBasicInfoProcessing, setIsAiBasicInfoProcessing] = useState(false);

  // 备注编辑状态
  const [isEditingRemarks, setIsEditingRemarks] = useState(false);
  const [remarksText, setRemarksText] = useState("");
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [draggingId, setDraggingId] = useState<string | null>(null);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(clientData);
      setInsight(data);
    } catch (e) { console.error(e); } finally { setLoadingInsight(false); }
  };

  const handleDrop = useCallback((sourceId: string, targetId: string) => {
    if (sourceId === targetId) return;
    setLocalTeam(prev => prev.map(m => m.id === sourceId ? { ...m, reportsTo: targetId } : m));
  }, []);

  const handleAiUpdateMaker = async () => {
    if (!aiInputText.trim()) return;
    setIsAiProcessing(true);
    try {
      const result = await parseDecisionMakerEdit(aiInputText);
      if (isAddingNew) {
        const newMaker: DecisionMaker = { ...result, id: `dm-${Date.now()}`, department: result.department || '未知' };
        setLocalTeam(prev => [...prev, newMaker]);
        setIsAddingNew(false);
      } else if (selectedMaker) {
        const updated = { ...selectedMaker, ...result };
        setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
        setSelectedMaker(updated);
      }
      setAiInputText(""); setIsAiEditing(false);
    } catch (e) { alert("AI 解析失败"); } finally { setIsAiProcessing(false); }
  };

  const handleAiUpdateBasicInfo = async (inputText: string) => {
    setIsAiBasicInfoProcessing(true);
    try {
      // 1. 提取各维度的变动
      const extracted = await extractCorporateBasicInfo(inputText);
      const today = new Date().toISOString().split('T')[0];

      const updatedInfo = { ...localBasicInfo };
      const tasks: Promise<void>[] = [];

      // 2. 针对有变动的维度进行历史追加和重新总结
      Object.keys(extracted).forEach((key) => {
        const fieldKey = key as keyof CorporateBasicInfo;
        const rawContent = extracted[key];

        if (rawContent && rawContent.trim()) {
          const current = localBasicInfo[fieldKey] || { summary: '', history: [] };
          const newEntry = {
            id: `ai-${Date.now()}-${fieldKey}`,
            date: today,
            content: rawContent
          };
          const newHistory = [newEntry, ...(current.history || [])];

          // 异步调用总结接口
          const task = summarizeCategoryHistory(SECTION_LABELS[fieldKey] || fieldKey, newHistory)
            .then(newSummary => {
              updatedInfo[fieldKey] = {
                summary: newSummary,
                history: newHistory
              };
            });
          tasks.push(task);
        }
      });

      await Promise.all(tasks);
      setLocalBasicInfo({ ...updatedInfo });
    } catch (e) {
      console.error(e);
      alert("AI 背景解析或总结失败，请检查网络或重试。");
    } finally {
      setIsAiBasicInfoProcessing(false);
    }
  };

  const toggleBusiness = (biz: string) => {
    if (!selectedMaker) return;
    const current = selectedMaker.responsibleBusiness || [];
    const next = current.includes(biz) ? current.filter(b => b !== biz) : [...current, biz];
    const updated = { ...selectedMaker, responsibleBusiness: next };
    setSelectedMaker(updated);
    setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  return (
    <div className="max-w-7xl mx-auto pb-12 space-y-8 animate-in fade-in duration-300 text-left">
      {/* 基本信息头部 (支持编辑) */}
      <ClientBasicInfoCard 
        client={clientData} 
        onClientUpdate={setClientData}
      />

      {/* 1. 客户基本情况卡片 */}
      <CorporateBasicInfoCard 
        data={localBasicInfo} 
        onUpdate={setLocalBasicInfo}
        onAiUpdate={handleAiUpdateBasicInfo}
        isAiProcessing={isAiBasicInfoProcessing}
      />

      {/* 2. 实时动态 */}
      <ClientDynamicsCard dynamics={clientData.dynamics} />

      {/* 3. 关键角色 (组织图谱) */}
      <OrgChartCard 
        localTeam={localTeam}
        onAddClick={() => { setIsAddingNew(true); setIsAiEditing(true); }}
        onMakerClick={(m) => { setSelectedMaker(m); setIsEditingRemarks(false); }}
        onDrop={handleDrop}
        draggingId={draggingId}
        setDraggingId={setDraggingId}
      />

      {/* 4. 拜访记录 */}
      <VisitHistoryCard history={clientData.visitHistory} />

      {/* 5. 财务表现 (预算执行情况) */}
      <FinancialPerformanceCard client={clientData} />

      {/* 6. App 矩阵 (产品矩阵) */}
      <AppMatrixCard matrix={clientData.appMatrix} onNavigate={onNavigateToApp} />

      {/* 模态框组省略... */}
      {selectedMaker && (
        <DecisionMakerModal 
          maker={selectedMaker}
          onClose={() => setSelectedMaker(null)}
          onAiEditClick={() => { setIsAddingNew(false); setIsAiEditing(true); }}
          onToggleBusiness={toggleBusiness}
          isEditingRemarks={isEditingRemarks}
          remarksText={remarksText}
          setRemarksText={setRemarksText}
          onStartEditRemarks={() => { setRemarksText(selectedMaker.remarks); setIsEditingRemarks(true); }}
          onSaveRemarks={() => {
            const updated = { ...selectedMaker, remarks: remarksText };
            setSelectedMaker(updated);
            setLocalTeam(prev => prev.map(m => m.id === updated.id ? updated : m));
            setIsEditingRemarks(false);
          }}
          onDeleteClick={() => setShowDeleteConfirm(true)}
        />
      )}

      {showDeleteConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => setShowDeleteConfirm(false)}></div>
          <div className="bg-white rounded-xl border border-slate-200 w-full max-w-sm relative overflow-hidden shadow-2xl p-8 text-center">
            <div className="w-16 h-16 bg-rose-50 text-rose-600 rounded-full flex items-center justify-center mx-auto mb-6"><AlertCircle size={32}/></div>
            <h4 className="text-lg font-black text-slate-900 mb-2">确认删除？</h4>
            <div className="flex gap-4 mt-8">
              <button onClick={() => setShowDeleteConfirm(false)} className="flex-1 px-4 py-3 border border-slate-200 text-slate-600 text-[10px] font-black uppercase tracking-widest rounded-lg">取消</button>
              <button onClick={() => {
                setLocalTeam(prev => prev.filter(m => m.id !== selectedMaker?.id));
                setSelectedMaker(null); setShowDeleteConfirm(false);
              }} className="flex-1 px-4 py-3 bg-rose-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg">确认删除</button>
            </div>
          </div>
        </div>
      )}

      {isAiEditing && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => !isAiProcessing && setIsAiEditing(false)}></div>
          <div className="bg-white rounded-xl border border-slate-200 w-full max-w-lg relative overflow-hidden shadow-2xl animate-in fade-in duration-200 p-8 text-left text-slate-900">
            <div className="flex items-center gap-2 mb-6">
              <Sparkles className="text-blue-600" size={18}/>
              <h4 className="text-xs font-black uppercase tracking-widest">{isAddingNew ? 'AI 智能新增' : 'AI 更新背景'}</h4>
            </div>
            <textarea 
              value={aiInputText} onChange={(e) => setAiInputText(e.target.value)}
              placeholder="输入描述信息..."
              className="w-full h-32 p-4 text-sm font-bold border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 bg-white"
            />
            <div className="flex justify-end gap-3">
              <button onClick={() => setIsAiEditing(false)} className="px-6 py-2.5 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-900">取消</button>
              <button onClick={handleAiUpdateMaker} disabled={isAiProcessing} className="px-8 py-2.5 bg-blue-600 text-white text-xs font-black uppercase tracking-widest rounded-lg flex items-center gap-3 hover:bg-blue-700 shadow-lg shadow-blue-500/20">
                {isAiProcessing ? <Loader2 size={16} className="animate-spin"/> : <Sparkles size={16}/>} 立即同步
              </button>
            </div>
          </div>
        </div>
      )}

      {insight && <AiInsightModal insight={insight} onClose={() => setInsight(null)} />}

      <button onClick={handleGenerateInsight} disabled={loadingInsight} className="fixed bottom-10 right-10 bg-slate-950 text-white px-6 py-3 rounded-full font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all border border-slate-800 shadow-2xl flex items-center gap-3 z-50">
        {loadingInsight ? <Loader2 size={18} className="animate-spin"/> : <BrainCircuit size={18}/>} 生成 AI 分析报告
      </button>
    </div>
  );
};

