export const PlatformMatrixCard: React.FC<{ matrix: AppCKBProfile['platformMatrix'] }> = ({ matrix }) => {
  // Helper to format large numbers
  const formatNumber = (num: number) => {
    if (num >= 100000000) return `${(num / 100000000).toFixed(1)}亿`;
    if (num >= 10000) return `${(num / 10000).toFixed(1)}万`;
    return num.toLocaleString();
  };

  // Find max values for highlighting
  const maxDownloads = Math.max(...matrix.map(m => m.downloads));
  const maxUninstalls = Math.max(...matrix.map(m => m.uninstalls));
  const maxMAU = Math.max(...matrix.map(m => m.mau));

  const renderCell = (value: number, max: number, isNegativeNegative: boolean = false) => {
    const isMax = value === max;
    return (
      <div className={`flex items-center gap-2 ${isMax ? 'text-rose-600 font-black' : 'text-slate-900 font-bold'}`}>
        {isMax && <Crown size={12} className="fill-current"/>}
        {formatNumber(value)}
      </div>
    );
  };

  return (
    <section className="bg-white rounded border border-slate-200 p-8 mb-6 shadow-sm overflow-hidden">
      <div className="flex items-center gap-3 border-b border-slate-100 pb-4 mb-6">
        <div className="text-slate-900 bg-slate-100 p-1.5 rounded"><Globe size={16}/></div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">全平台分发表现</h3>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <th className="px-6 py-4 w-1/4">分发渠道</th>
              <th className="px-6 py-4 w-1/4">累计下载量</th>
              <th className="px-6 py-4 w-1/4">累计卸载量</th>
              <th className="px-6 py-4 w-1/4">月活用户 (MAU)</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((p, idx) => (
              <tr key={idx} className="hover:bg-slate-50 transition-colors group text-slate-700">
                <td className="px-6 py-5">
                  <span className={`text-xs font-black uppercase tracking-tight px-2 py-1 rounded ${p.platform === 'AppStore' ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-600'}`}>
                    {p.platform}
                  </span>
                </td>
                <td className="px-6 py-5 font-mono">
                  {renderCell(p.downloads, maxDownloads)}
                </td>
                <td className="px-6 py-5 font-mono">
                  {renderCell(p.uninstalls, maxUninstalls, true)}
                </td>
                <td className="px-6 py-5 font-mono">
                  {renderCell(p.mau, maxMAU)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
};

import { ClientStage, ClientProfile, MetricPoint, AppCKBProfile } from './types';

const generateHistory = (base: number, variance: number, days: number = 14): MetricPoint[] => {
  return Array.from({ length: days }).map((_, i) => ({
    date: `03-${(25 - days + i + 1).toString().padStart(2, '0')}`,
    value: base + (Math.random() - 0.5) * variance
  }));
};

const generateAnnualHistory = (baseMonthly: number) => {
  const months = ['1月', '2月', '3月', '4月', '5月', '6月', '7月', '8月', '9月', '10月', '11月', '12月'];
  const currentMonthIdx = 2; 
  return months.map((m, idx) => {
    const seasonality = 1 + Math.sin(idx / 2) * 0.2; 
    const forecastVal = baseMonthly * seasonality;
    const lastYearActual = baseMonthly * seasonality * (0.8 + Math.random() * 0.3);
    const actual = idx <= currentMonthIdx ? forecastVal * (0.95 + Math.random() * 0.1) : undefined;

    let forecast: number | undefined = undefined;
    if (idx === currentMonthIdx) {
      forecast = actual; 
    } else if (idx > currentMonthIdx) {
      forecast = forecastVal;
    }

    return {
      date: m,
      actual,
      forecast, 
      lastYearActual
    };
  });
};

