export const PlatformMatrixCard: React.FC<{ matrix: AppCKBProfile['platformMatrix'] }> = ({ matrix }) => {
  // Helper to format large numbers
  const formatNumber = (num: number) => {
    if (num >= 100000000) return `${(num / 100000000).toFixed(1)}亿`;
    if (num >= 10000) return `${(num / 10000).toFixed(1)}万`;
    return num.toLocaleString();
  };

  // Find max values for highlighting
  const maxDownloads = Math.max(...matrix.map(m => m.downloads));
  const maxUninstalls = Math.max(...matrix.map(m => m.uninstalls));
  const maxMAU = Math.max(...matrix.map(m => m.mau));

  const renderCell = (value: number, max: number, platformName: string, isNegativeNegative: boolean = false) => {
    // Explicitly do not highlight AppStore, as requested
    const isMax = value === max && platformName !== 'AppStore';

    return (
      <div className={`flex items-center gap-2 ${isMax ? 'text-rose-600 font-black' : 'text-slate-900 font-bold'}`}>
        {isMax && <Crown size={12} className="fill-current"/>}
        {formatNumber(value)}
      </div>
    );
  };

  return (
    <section className="bg-white rounded border border-slate-200 p-8 mb-6 shadow-sm overflow-hidden">
      <div className="flex items-center gap-3 border-b border-slate-100 pb-4 mb-6">
        <div className="text-slate-900 bg-slate-100 p-1.5 rounded"><Globe size={16}/></div>
        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">全平台分发表现</h3>
      </div>

